import os

def solve(arg1: dict) -> str:
    environment = arg1.get('environment', 'production')
    log_level = arg1.get('logLevel', 'info')
    message = arg1.get('message', '')

    if environment == 'development':
        if log_level == 'info':
            return f'Console log: {message}'
        elif log_level == 'error':
            return f'Console log: {message}'
    elif environment == 'production':
        if log_level == 'info':
            return f'Console log: {message}'
        elif log_level == 'error':
            return f'Console log: {message}'

    # Handle file logging only if not in a read-only filesystem
    if os.access('.', os.W_OK):
        log_dir = 'logs'
        if not os.path.exists(log_dir):
            os.makedirs(log_dir)
        log_file_path = os.path.join(log_dir, 'log.txt')
        with open(log_file_path, 'a') as log_file:
            log_file.write(message + '\n')
        return f'File log created with message: {message}'
    else:
        return 'No file log created'
